mapper.select:
SELECT t.id, t.account_id AS accountId, a.name AS accountName, t.category_id AS categoryId, c.name AS categoryName, t.type, t.amount, t.note, DATE_FORMAT(t.time, '%Y-%m-%d %H:%i:%s') AS time, t.transfer_id AS transferId, t.create_time AS createTime, t.update_time AS updateTime FROM `transaction` t LEFT JOIN account a ON t.account_id = a.id LEFT JOIN category c ON t.category_id = c.id WHERE t.user_id = #{userId}
AND t.account_id = #{accountId}
AND t.category_id = #{categoryId}
AND t.time >= #{startTime}
AND t.time <= #{endTime}
AND t.note LIKE CONCAT('%', #{keyword}, '%') ESCAPE '\\'
ORDER BY t.amount ASC
ORDER BY t.amount DESC
ORDER BY t.time DESC

SELECT COUNT(*)
FROM `transaction` t
WHERE t.user_id = #{userId}

  AND t.account_id = #{accountId}


  AND t.category_id = #{categoryId}


  AND t.time >= #{startTime}


  AND t.time <= #{endTime}


  AND t.note LIKE CONCAT('%', #{keyword}, '%') ESCAPE '\\'

SELECT t.category_id AS categoryId, c.name AS categoryName, c.type AS type, SUM(t.amount) AS totalAmount, COUNT(*) AS transactionCount FROM `transaction` t LEFT JOIN category c ON t.category_id = c.id WHERE t.user_id = #{userId} AND t.time >= #{startOfMonth} AND t.time < #{startOfNextMonth} AND t.transfer_id IS NULL
AND t.type = #{type}
GROUP BY t.category_id, c.name, c.type ORDER BY totalAmount DESC

SELECT COALESCE(SUM(t.amount), 0)
FROM `transaction` t
WHERE t.user_id = #{userId}
  AND t.account_id = #{accountId}
  AND t.type = 1

SELECT COALESCE(SUM(t.amount), 0)
FROM `transaction` t
WHERE t.user_id = #{userId}
  AND t.account_id = #{accountId}
  AND t.type = 2

SELECT t.account_id AS accountId, COALESCE(SUM(t.amount), 0) AS totalIncome FROM `transaction` t WHERE t.user_id = #{userId} AND t.account_id IN
#{id}
AND t.type = 1 GROUP BY t.account_id

SELECT t.account_id AS accountId, COALESCE(SUM(t.amount), 0) AS totalExpense FROM `transaction` t WHERE t.user_id = #{userId} AND t.account_id IN
#{id}
AND t.type = 2 GROUP BY t.account_id
